Here's an example graphene setup:

```python
import graphene
from graphene import relay
from graphene.contrib.sqlalchemy import SQLAlchemyNode, SQLAlchemyConnectionField
from app.models.thing import Thing as ThingModel

schema = graphene.Schema()

@schema.register
class Thing(SQLAlchemyNode):
    class Meta:
        model = ThingModel

class Query(graphene.ObjectType):
    all_things = SQLAlchemyConnectionField(Thing, id=graphene.Int(), ids=graphene.List(graphene.Int()), description="All the things!")
    node = relay.NodeField()
    
    def resolve_all_things(self, args, info):
        ids = args.get('ids')
        
        # Handle queries passing an empty `ids` list []
        if ids is not None:
            # If we got an empty `ids` list []
            if len(ids) == 0:
                # This is definitely getting executed, yay!
                # BUT the empty list is apparently replaced with the full set :-O
                return []
            
            # If we got a non-empty `ids` list like [1,2,3], find and return those objects
            return ThingModel.query.filter(ThingModel.id.in_(ids)).all()

        # This no-args fallback is definitely not getting executed,
        # which is correct when demonstrating the issue at hand
        return ThingModel.query.order_by(ThingModel.created_at).all()
```

